export const modules = Object.values(MODULE_META).map((meta) => ({
  ...meta,
  phrases: phrasalVerbsByModule[meta.id],
}));

export const allPhrasalVerbs = modules.flatMap((module) =>
  module.phrases.map((phrase) => ({
    ...phrase,
    moduleId: module.id,
  })),
);

export function getModuleById(moduleId) {
  return modules.find((module) => module.id === Number(moduleId));
}

